import React from "react";
import classes from './KPVBlock.module.css'

import Scroll from "../../Scroll/Scroll"

import image from './images/image.jpg'

export default function KPVBlock() {
    const [isVisible, setIsVisible] = React.useState(false)
    const onVisible = () => {
        setIsVisible(true)
    }
    return (
        <Scroll className={classes.block} onVisible={onVisible}>
            <div className={[classes.col_1, (isVisible ? 'fadeIn' : '')].join(' ')}>
                <img src={image} alt="kpv-image" />
            </div>
            <div className={classes.col_2}>
                <div className={['headline-font', classes.title, (isVisible ? 'fadeIn' : '')].join(' ')}>
                    <div>Kingdom <br /> Properties</div>
                    <div className={classes.x}>X</div>
                    <div style={{marginTop: '-10px'}}>Versace</div>
                </div>
                <div className={[classes.text, (isVisible ? 'fadeIn' : '')].join(' ')}>Kingdom Properties is a member of Moafaq Al Gaddah Group (MAG), a group of Companies which was established in the UAE in 1978, as traders in car parts, batteries and tires. Today, it is a multinational organization with 18 offices in eight different countries throughout Europe, the Middle East and Asia. Today, there is a collaboration with Versace brand to make the skyscrapper an exclusive. OASIS reveals an exclusive NFT collection in partnership with Kingdom Properties, inspired by the iconic skyscraper in Dubai which is build in collaboration with Versace</div>
            </div>
        </Scroll>
    )
}
