import React from "react";
import classes from './BackgroundBlock.module.css'

import FluidSim from "./scripts/fluidSim";

export default function BackgroundBlock () {
    const firstRender = React.useRef(true)
    const canvasRef = React.useRef(null)
    const containerRef = React.useRef(null)


    React.useEffect(() => {
        if (firstRender.current) {
            if (canvasRef.current !== null && containerRef.current !== null) {
                FluidSim(canvasRef.current, document.body)
                firstRender.current = false
            }
        }
    }, [canvasRef, containerRef])
    return (
        <div className={classes.block}>
            <div ref={containerRef} className={classes.container}></div>
            <canvas ref={canvasRef} className={classes.mouseFluid}/>
        </div>
    )
}
