import React from "react";
import Marquee from "react-marquee-slider";
import classes from './PenthouseOverviewBlock.module.css'

import Scroll from "../../Scroll/Scroll"

// Ground Floor Slides
import floor_0_slide_1 from './images/slides/0_floor/slide-1.jpg'
import floor_0_slide_2 from './images/slides/0_floor/slide-2.jpg'
import floor_0_slide_3 from './images/slides/0_floor/slide-3.jpg'
import floor_0_slide_4 from './images/slides/0_floor/slide-4.jpg'
import floor_0_slide_5 from './images/slides/0_floor/slide-5.jpg'
import floor_0_slide_6 from './images/slides/0_floor/slide-6.jpg'
import floor_0_slide_7 from './images/slides/0_floor/slide-7.jpg'
import floor_0_slide_8 from './images/slides/0_floor/slide-8.jpg'
import floor_0_slide_9 from './images/slides/0_floor/slide-9.jpg'
import floor_0_slide_10 from './images/slides/0_floor/slide-10.jpg'
// First Floor Slides
import floor_1_slide_1 from './images/slides/1_floor/slide-1.jpg'
import floor_1_slide_2 from './images/slides/1_floor/slide-2.jpg'
import floor_1_slide_3 from './images/slides/1_floor/slide-3.jpg'
import floor_1_slide_4 from './images/slides/1_floor/slide-4.jpg'
import floor_1_slide_5 from './images/slides/1_floor/slide-5.jpg'
import floor_1_slide_6 from './images/slides/1_floor/slide-6.jpg'
import floor_1_slide_7 from './images/slides/1_floor/slide-7.jpg'
import floor_1_slide_8 from './images/slides/1_floor/slide-8.jpg'
import floor_1_slide_9 from './images/slides/1_floor/slide-9.jpg'
import floor_1_slide_10 from './images/slides/1_floor/slide-10.jpg'
import floor_1_slide_11 from './images/slides/1_floor/slide-11.jpg'
import floor_1_slide_12 from './images/slides/1_floor/slide-12.jpg'
import floor_1_slide_13 from './images/slides/1_floor/slide-13.jpg'
// Second Floor Slides
import floor_2_slide_1 from './images/slides/2_floor/slide-1.jpg'
import floor_2_slide_2 from './images/slides/2_floor/slide-2.jpg'
import floor_2_slide_3 from './images/slides/2_floor/slide-3.jpg'
import floor_2_slide_4 from './images/slides/2_floor/slide-4.jpg'
import floor_2_slide_5 from './images/slides/2_floor/slide-5.jpg'
import floor_2_slide_6 from './images/slides/2_floor/slide-6.jpg'
import floor_2_slide_7 from './images/slides/2_floor/slide-7.jpg'
import floor_2_slide_8 from './images/slides/2_floor/slide-8.jpg'
import floor_2_slide_9 from './images/slides/2_floor/slide-9.jpg'
import floor_2_slide_10 from './images/slides/2_floor/slide-10.jpg'
import floor_2_slide_11 from './images/slides/2_floor/slide-11.jpg'
import floor_2_slide_12 from './images/slides/2_floor/slide-12.jpg'
import floor_2_slide_13 from './images/slides/2_floor/slide-13.jpg'
import floor_2_slide_14 from './images/slides/2_floor/slide-14.jpg'


export default function PenthouseOverviewBlock() {
    const [slides] = React.useState([
        // Ground Floor Slides
        floor_0_slide_1,
        floor_0_slide_2,
        floor_0_slide_3,
        floor_0_slide_4,
        floor_0_slide_5,
        floor_0_slide_6,
        floor_0_slide_7,
        floor_0_slide_8,
        floor_0_slide_9,
        floor_0_slide_10,
        // // First Floor Slides
        floor_1_slide_1,
        floor_1_slide_2,
        floor_1_slide_3,
        floor_1_slide_4,
        floor_1_slide_5,
        floor_1_slide_6,
        floor_1_slide_7,
        floor_1_slide_8,
        floor_1_slide_9,
        floor_1_slide_10,
        floor_1_slide_11,
        floor_1_slide_12,
        floor_1_slide_13,
        // Second Floor Slides
        floor_2_slide_1,
        floor_2_slide_2,
        floor_2_slide_3,
        floor_2_slide_4,
        floor_2_slide_5,
        floor_2_slide_6,
        floor_2_slide_7,
        floor_2_slide_8,
        floor_2_slide_9,
        floor_2_slide_10,
        floor_2_slide_11,
        floor_2_slide_12,
        floor_2_slide_13,
        floor_2_slide_14
    ])
    const isVisibleRef = React.useRef(false)
    const [isVisible, setIsVisible] = React.useState(false)
    const onVisible = () => {
        if (!isVisibleRef.current) {
            isVisibleRef.current = true
            setIsVisible(true)
        }
    }
    return (
        <Scroll className={classes.block} onVisible={onVisible} POV={0.05}>
            <div className={['headline-font', classes.title, (isVisible ? 'fadeIn' : '')].join(' ')}>Penthouse<br/>Overview</div>
            <div className={classes.slider_wrapper}>
                <Marquee  velocity={isVisible ? 15 : 0}>
                    {slides.map((slide, index) => <img src={slide} alt={`slide-${index+1}`} key={`slide-${index+1}`} className={classes.slide} />)}
                </Marquee>
            </div>
        </Scroll>
    )
}
