import React from "react"
import classes from './RoadMapBlock.module.css'

import Scroll from "../../Scroll/Scroll"

export default function RoadMapBlock () {
    const [slide, setSlide] = React.useState(1)
    const [isBack, setIsBack] = React.useState(false)
    const [isChangeOneSlide, setIsChangeOneSlide] = React.useState(true)
    const [isChanging, setIsChanging] = React.useState(false)
    const [isVisible, setIsVisible] = React.useState(false)
    const [slides] = React.useState({
        1: classes.slide_1,
        2: classes.slide_2,
        3: classes.slide_3,
        4: classes.slide_4,
    })
    const changeSlide = (id) => {
        if (id === slide) {
            return
        }

        if (Math.abs(slide - id) === 1) {
            setIsChangeOneSlide(true)
        } else {
            setIsChangeOneSlide(false)
        }

        if (id - slide < 0) {
            setIsBack(true)
        } else {
            setIsBack(false)
        }

        setIsChanging(true)
        setTimeout(() => {
            setSlide(id)
            setIsChanging(false)
        }, 400)
    }

    const onVisible = () => {
        setIsVisible(true)
    }

    return (
        <Scroll className={[classes.block, (slides[slide])].join(' ')} onVisible={onVisible}>
            <div>
                <div className={["headline-font", classes.headline, (isVisible ? 'fadeIn' : '')].join(' ')}>Road map</div>
                <div className={[classes.title, (isVisible ? 'fadeIn' : '')].join(' ')}>We are not the project you will soon forget of, we are the future</div>
            </div>
            <div className={classes.slides_container}>
                {slide === 1 &&
                    <div className={classes.slide}>
                        <div className={[classes.slide__title, (
                            isChanging ? 'fadeOutUp' : 'fadeInDown'
                        )].join(' ')}>Phase 01 - Completed</div>
                        <div className={[classes.slide__subtitle, (
                            isChanging ? 'fadeOutUp' : 'fadeInDown'
                        )].join(' ')}>THE BEGINNING</div>
                        <div className={classes.slide__content}>
                            <div className={[classes.slide__content__item, (
                                isChanging ? 'fadeOutRight' : 'fadeInRight'
                            )].join(' ')}>
                                <div className={classes.slide__content__item__marker} />
                                Analysis of blockchain capabilities
                            </div>
                            <div className={[classes.slide__content__item, (
                                isChanging ? 'fadeOutRight' : 'fadeInRight'
                            )].join(' ')}>
                                <div className={classes.slide__content__item__marker} />
                                Ideas drafts
                            </div>
                            <div className={[classes.slide__content__item, (
                                isChanging ? 'fadeOutRight' : 'fadeInRight'
                            )].join(' ')}>
                                <div className={classes.slide__content__item__marker} />
                                Building the network
                            </div>
                            <div className={[classes.slide__content__item, (
                                isChanging ? 'fadeOutRight' : 'fadeInRight'
                            )].join(' ')}>
                                <div className={classes.slide__content__item__marker} />
                                1st NFT Collection development
                            </div>
                        </div>
                    </div>
                }

                {slide === 2 && <div className={classes.slide}>
                    <div className={[classes.slide__title, (
                        isChanging ? 'fadeOutUp' : 'fadeInDown'
                    )].join(' ')}>Phase 02 - We’re here</div>
                    <div className={[classes.slide__subtitle, (
                        isChanging ? 'fadeOutUp' : 'fadeInDown'
                    )].join(' ')}>THE EVOLUTION</div>
                    <div className={classes.slide__content}>
                        <div className={[classes.slide__content__item, (
                            isChanging ? 'fadeOutRight' : 'fadeInRight'
                        )].join(' ')}>
                            <div className={classes.slide__content__item__marker} />
                            Drop of the 1st NFT Collection
                        </div>
                        <div className={[classes.slide__content__item, (
                            isChanging ? 'fadeOutRight' : 'fadeInRight'
                        )].join(' ')}>
                            <div className={classes.slide__content__item__marker} />
                            Raffle of the penthouse for the community
                        </div>
                        <div className={[classes.slide__content__item, (
                            isChanging ? 'fadeOutRight' : 'fadeInRight'
                        )].join(' ')}>
                            <div className={classes.slide__content__item__marker} />
                            2nd NFT Collection development
                        </div>
                        <div className={[classes.slide__content__item, (
                            isChanging ? 'fadeOutRight' : 'fadeInRight'
                        )].join(' ')}>
                            <div className={classes.slide__content__item__marker} />
                            Drop of the 2nd NFT Collection
                        </div>
                        <div className={[classes.slide__content__item, (
                            isChanging ? 'fadeOutRight' : 'fadeInRight'
                        )].join(' ')}>
                            <div className={classes.slide__content__item__marker} />
                            Luxury cars raffle
                        </div>
                        <div className={[classes.slide__content__item, (
                            isChanging ? 'fadeOutRight' : 'fadeInRight'
                        )].join(' ')}>
                            <div className={classes.slide__content__item__marker} />
                            IDO Token Development
                        </div>
                    </div>
                </div>}
                {slide === 3 && <div className={classes.slide}>
                    <div className={[classes.slide__title, (
                        isChanging ? 'fadeOutUp' : 'fadeInDown'
                    )].join(' ')}>Phase 03</div>
                    <div className={[classes.slide__subtitle, (
                        isChanging ? 'fadeOutUp' : 'fadeInDown'
                    )].join(' ')}>THE REVOLUTION</div>
                    <div className={classes.slide__content}>
                        <div className={[classes.slide__content__item, (
                            isChanging ? 'fadeOutRight' : 'fadeInRight'
                        )].join(' ')}>
                            <div className={classes.slide__content__item__marker} />
                            IDO-launching a token for holders
                        </div>
                        <div className={[classes.slide__content__item, (
                            isChanging ? 'fadeOutRight' : 'fadeInRight'
                        )].join(' ')}>
                            <div className={classes.slide__content__item__marker} />
                            Airdrop
                        </div>
                        <div className={[classes.slide__content__item, (
                            isChanging ? 'fadeOutRight' : 'fadeInRight'
                        )].join(' ')}>
                            <div className={classes.slide__content__item__marker} />
                            Building the metaverse
                        </div>
                    </div>
                </div>}
                {slide === 4 && <div className={classes.slide}>
                    <div className={[classes.slide__title, (
                        isChanging ? 'fadeOutUp' : 'fadeInDown'
                    )].join(' ')}>Phase 04</div>
                    <div className={[classes.slide__subtitle, (
                        isChanging ? 'fadeOutUp' : 'fadeInDown'
                    )].join(' ')}>BUILDING THE FUTURE</div>
                    <div className={classes.slide__content}>
                        <div className={[classes.slide__content__item, (
                            isChanging ? 'fadeOutRight' : 'fadeInRight'
                        )].join(' ')}>
                            <div className={classes.slide__content__item__marker} />
                            All holders will get the opportunity to transfer their NFT into a Metaverse
                        </div>
                        <div className={[classes.slide__content__item, (
                            isChanging ? 'fadeOutRight' : 'fadeInRight'
                        )].join(' ')}>
                            <div className={classes.slide__content__item__marker} />
                            New NFT-cards with unique features
                        </div>
                        <div className={[classes.slide__content__item, (
                            isChanging ? 'fadeOutRight' : 'fadeInRight'
                        )].join(' ')}>
                            <div className={classes.slide__content__item__marker} />
                            Collaboration with the worldwide brands
                        </div>
                    </div>
                </div>}
            </div>
            <div className={[classes.pagination, (
                    isBack ? classes.pagination__back_animation : ''
                ), (
                    !isChangeOneSlide ? classes.with_delay : ''
                )].join(' ')}>
                <div className={[classes.pagination__start_line, (
                    slide >= 1 ? classes.pagination__line__active : ''
                )].join(' ')}></div>
                <div className={[classes.pagination__item, (
                    slide >= 1 ? classes.pagination__item__active : ''
                )].join(' ')} onClick={() => changeSlide(1)}>
                    1
                </div>
                <div className={[classes.pagination__line, (
                    slide >= 2 ? classes.pagination__line__active : ''
                )].join(' ')}></div>
                <div className={[classes.pagination__item, (
                    slide >= 2 ? classes.pagination__item__active : ''
                )].join(' ')} onClick={() => changeSlide(2)}>
                    2
                </div>
                <div className={[classes.pagination__line, (
                    slide >= 3 ? classes.pagination__line__active : ''
                )].join(' ')}></div>
                <div className={[classes.pagination__item, (
                    slide >= 3 ? classes.pagination__item__active : ''
                )].join(' ')} onClick={() => changeSlide(3)}>
                    3
                </div>
                <div className={[classes.pagination__line, (
                    slide === 4 ? classes.pagination__line__active : ''
                )].join(' ')}></div>
                <div className={[classes.pagination__item, (
                    slide === 4 ? classes.pagination__item__active : ''
                )].join(' ')} onClick={() => changeSlide(4)}>
                    4
                </div>
                <div className={[classes.pagination__end_line, (
                    slide === 4 ? classes.pagination__line__active : ''
                )].join(' ')}></div>
            </div>
        </Scroll>
    )
}
