import React from 'react'
import image from './images/image.png'
import classes from './FirstBlock.module.css'

export default function FirstBlock () {
    const [isVisibleHeadline, setIsVisibleHeadline] = React.useState(false)
    const [isVisibleTitle, setIsVisibleTitle] = React.useState(false)
    React.useEffect(() => {
        setTimeout(() => {
            setIsVisibleHeadline(true)
        }, 200)
        setTimeout(() => {
            setIsVisibleTitle(true)
        }, 500)
    }, [])
    return (
        <div className={classes.block}>
            <img src={image} alt="image" className={classes.image} />
            <div className={['headline-font', classes.headline,
                    (isVisibleHeadline ? 'fadeIn' : '')
                ].join(' ')}>
                <span className={classes.selected}>EXCLUSIVE</span> ACCESS TO <br /> OASIS METAVERSE
            </div>
            <div className={[classes.title, (isVisibleTitle ? 'fadeIn' : '')].join(' ')}>LAUNCHING SOON</div>
        </div>
    )
}
