import React from "react"
import classes from './MissionBlock.module.css'

import Scroll from '../../Scroll/Scroll'

import image_1 from './images/Image_1.jpg'
import image_2 from './images/Image_2.jpg'
import image_3 from './images/Image_3.jpg'

export default function MissionBlock () {
    let [isVisibleHeadline, setIsVisibleHeadline] = React.useState(false)
    let [isVisibleDescription, setIsVisibleDescription] = React.useState(false)
    let [MT, setMT] = React.useState(0)
    let [textTop, setTextTop] = React.useState(0)
    let scrollRef = React.useRef(null)
    let isVisible = React.useRef(false)
    const onHide = () => {
        isVisible.current = false
    }
    const onVisible = () => {
        setIsVisibleHeadline(true)
        setIsVisibleDescription(true)
        isVisible.current = true
    }
    const onScroll = ({prev, current, direction}) => {
        let k = 1.5
        if (/Android|webOS|iPhone|iPad|iPod|BlackBerry|BB|PlayBook|IEMobile|Windows Phone|Kindle|Silk|Opera Mini/i.test(navigator.userAgent) || window.innerWidth <= 778) {
            k = 12.5
        }
        if (isVisible.current && prev !== 0) {
            setMT(p => {
                if (direction === `down`) {
                    return (p-(prev/(current*k)))
                } else {
                    return (p+(prev/(current*k)))
                }
            })
        }
    }

    return (
        <Scroll get={scrollRef} className={classes.block} onVisible={onVisible} onScrolling={onScroll} onHide={onHide} style={{backgroundPositionY: `calc(50% + ${MT*2}px)`}}>
            <div style={{display: 'flex', flexDirection: 'column', rowGap: '32px', marginBottom: '74px'}}>
                <div className={['headline-font', classes.headline, (isVisibleHeadline ? 'fadeIn' : '')].join(' ')}>MISSION</div>
                <div className={[classes.description, (isVisibleDescription ? 'fadeIn' : '')].join(' ')}>Our mission is to revolutionize the digital world by connecting it with luxury real estate. OASIS not only unlocks private club membership but gains access to be in the center  of evolution in the construction industry in the metaverse. We give you the opportunity to build the future together. You think it is impossible? We assure you, it is not.</div>
            </div>
            <div className={classes.images}>
                <img src={image_1} alt="1" className={[classes.image, classes.image_1].join(' ')} style={{transform: `translateY(${MT}px)`}} />
                <div className={classes.image_2_container}>
                    <img src={image_2} alt="2" className={[classes.image, classes.image_2].join(' ')} style={{transform: `translateY(-${MT/2}px)`}} />
                    <div className={['headline-font', classes.text].join(' ')} style={{transform: `translateY(${MT}px)`}} >OASIS</div>
                </div>
                <img src={image_3} alt="3" className={[classes.image, classes.image_3].join(' ')} style={{transform: `translateY(${MT}px)`}} />
            </div>
        </Scroll>
    )
}
