import React from "react"

export default function Navigation ({startSection, children}) {
    let [sections, setSections] = React.useState({})
    let [history, setHistory] = React.useState([startSection])
    let [loaded, setLoaded] = React.useState(false)

    let [navigation] = React.useState({
        setSection(section, data = {}) {
            window.scrollTo(0, 0)
            setHistory((prev) => [
                ...prev, {section, data}
            ])
        },
        back() {
            setHistory((prev) => {
                if (prev.length - 1 < 1) {
                    return prev
                }
                return prev.slice(0, prev.length - 1)
            })
            return true
        }
    })
    React.useEffect(() => {
        setLoaded(false)
        let tmp = {}
        React.Children.map(children, (child, i) => {
            tmp[child.props.id] = React.cloneElement(child, {
                navigation
            })
        })
        setSections(tmp)
        setLoaded(true)
    }, [children])
    return (
        <>
            {loaded && (React.cloneElement(sections[history[history.length - 1].section], {
                            data: history[history.length - 1].data
                        })
            )}
        </>
    )
}
