import React from 'react'
import classes from './SecondBlock.module.css'

import Scroll from '../../Scroll/Scroll'

export default function SecondBlock () {
    const [isVisibleHeadline, setIsVisibleHeadline] = React.useState(false)
    const [isVisibleDescription, setIsVisibleDescription] = React.useState(false)
    const onVisible = () => {
        setIsVisibleHeadline(true)
        setIsVisibleDescription(true)
    }
    return (
        <Scroll className={classes.block} onVisible={onVisible}>
            <div className={["headline-font", classes.headline, (isVisibleHeadline ? 'fadeIn' : '')].join(' ')}>
                The journey into the <br />
                <span className={classes.selected}>metaverse</span> begins
            </div>
            <div className={[classes.description, (isVisibleDescription ? 'fadeIn' : '')].join(' ')}>
                OASIS is opening up access to their world with the launch of the OASIS NFT community. OASIS is people. People who believe in an idea. People who have vast experience in the crypto market behind them. People who are ready to build an innovative project from scratch.Collectors will be able to join the unique UAE project as they take members o on a journey to experience the world of real estate in the metaverse and beyond. The upcoming metaverse is the exclusive land with your own elite real estates and luxury property which you can transfer from your NFT Collections, use them, upgrade or sell and earn tokens. NFT holders have an access to enjoy the metaverse first.
            </div>
        </Scroll>
    )
}
